svg.script:
  (function () {
  var svg = document.documentElement;
  svg._chartInit = function (svgEl, ctx) {
    var dataLayerEl = document.getElementById('data-layer');
    var legendRoot = document.getElementById('legend-root');
    var xLabelsEl = document.getElementById('x-labels');

    var TOTAL = 819293;
    var SCALE_Y = 400 / TOTAL;
    var COL_W = 160;
    var COL_GAP = 4;
    var REVEAL_DURATION = 0.8;
    var COL_START = [0, 0.25, 0.50, 0.75, 1.00];
    var COL_ANIM_WINDOW = 1.0;

    function colX(depth) { return 68 + depth * (COL_W + COL_GAP); }

    var nodes = [
      ['flare',819293,0,1],
      ['analytics',48716,1,1],['animate',93278,1,2],['data',30284,1,3],
      ['display',24254,1,4],['flex',4877,1,5],['physics',29934,1,6],
      ['query',75492,1,7],['scale',31294,1,8],['util',91480,1,2],['vis',389684,1,3],
      ['cluster',15207,2,1],['graph',26435,2,1],['optimization',7074,2,1],
      ['Easing',17010,2,2],['FunctionSequence',5842,2,2],['interpolate',23457,2,2],
      ['Parallel',5176,2,2],['Scheduler',5593,2,2],['Sequence',5534,2,2],
      ['Transition',9201,2,2],['Transitioner',19975,2,2],
      ['converters',18349,2,3],['DataField',1759,2,3],['DataSchema',2165,2,3],
      ['DataSource',3331,2,3],['DataUtil',3322,2,3],
      ['DirtySprite',8833,2,4],['LineSprite',1732,2,4],['RectSprite',3623,2,4],['TextSprite',10066,2,4],
      ['FlexSprite',4877,2,5],
      ['NBodyForce',10498,2,6],['Particle',2822,2,6],['Simulation',9983,2,6],
      ['Spring',2213,2,6],['SpringForce',1681,2,6],
      ['AggregateExpression',1616,2,7],['Arithmetic',3891,2,7],['Comparison',5103,2,7],
      ['DateUtil',4141,2,7],['Expression',5130,2,7],['Fn',3240,2,7],
      ['Query',13896,2,7],['StringUtil',4130,2,7],
      ['LogScale',3151,2,8],['OrdinalScale',3770,2,8],['QuantitativeScale',4839,2,8],
      ['Scale',4268,2,8],['TimeScale',5833,2,8],
      ['Arrays',8258,2,2],['Colors',10001,2,2],['Dates',8217,2,2],['Displays',12555,2,2],
      ['Geometry',10993,2,2],['math',9346,2,2],['Property',5559,2,2],
      ['Sort',6887,2,2],['Stats',6557,2,2],
      ['axis',33886,2,3],['controls',53040,2,3],['vis_data',110230,2,3],
      ['legend',36003,2,3],['operator',139985,2,3],
      ['Axis',24593,3,3],['CartesianAxes',6703,3,3],
      ['AnchorControl',2138,3,3],['ClickControl',3824,3,3],['ControlList',4665,3,3],
      ['DragControl',2649,3,3],['HoverControl',4896,3,3],
      ['NavigationControl',7862,3,3],['PanZoomControl',5771,3,3],
      ['SelectionControl',7852,3,3],['TooltipControl',8435,3,3],
      ['Data',20544,3,3],['DataList',19788,3,3],['DataSprite',10349,3,3],
      ['NodeSprite',19382,3,3],['render',8514,3,3],['ScaleBinding',11275,3,3],['Tree',7147,3,3],
      ['Legend',20859,3,3],['LegendItem',4614,3,3],['LegendRange',10530,3,3],
      ['distortion',14219,3,3],['encoder',10759,3,3],['filter_op',11893,3,3],
      ['label',17057,3,3],['layout',67804,3,3],
      ['AxisLayout',6702,4,3],['CircleLayout',5618,4,3],['CirclePackingLayout',12003,4,3],
      ['ForceDirectedLayout',8411,4,3],['IcicleTreeLayout',4864,4,3],
      ['RadialTreeLayout',7982,4,3],['StackedAreaLayout',9121,4,3],
      ['BifocalDistortion',4461,4,3],['Distortion',6314,4,3],['FisheyeDistortion',3444,4,3]
    ];

    var yPos = {
      'flare':100,
      'analytics':100,'animate':123.8,'data':169.5,'display':184.3,'flex':199.1,
      'physics':201.1,'query':214.8,'scale':251.5,'util':265.2,'vis':310.3,
      'cluster':100,'graph':107.4,'optimization':120.2,
      'Easing':123.8,'FunctionSequence':132.0,'interpolate':134.8,
      'Parallel':143.2,'Scheduler':145.7,'Sequence':147.9,'Transition':150.2,'Transitioner':153.9,
      'converters':169.5,'DataField':178.5,'DataSchema':179.3,'DataSource':180.3,'DataUtil':181.9,
      'DirtySprite':184.3,'LineSprite':188.6,'RectSprite':189.4,'TextSprite':190.8,
      'FlexSprite':199.1,
      'NBodyForce':201.1,'Particle':206.2,'Simulation':207.5,'Spring':212.3,'SpringForce':213.4,
      'AggregateExpression':214.8,'Arithmetic':215.6,'Comparison':217.5,'DateUtil':221.2,
      'Expression':223.5,'Fn':225.8,'Query':227.4,'StringUtil':234.0,
      'LogScale':251.5,'OrdinalScale':252.9,'QuantitativeScale':254.4,'Scale':256.1,'TimeScale':257.6,
      'Arrays':265.2,'Colors':268.6,'Dates':272.4,'Displays':275.8,'Geometry':281.6,
      'math':286.4,'Property':290.2,'Sort':292.5,'Stats':295.1,
      'axis':310.3,'controls':323.8,'vis_data':347.0,'legend':374.2,'operator':388.7,
      'Axis':310.3,'CartesianAxes':322.2,
      'AnchorControl':323.8,'ClickControl':324.8,'ControlList':326.5,'DragControl':329.0,
      'HoverControl':330.2,'NavigationControl':332.6,'PanZoomControl':336.1,
      'SelectionControl':338.7,'TooltipControl':342.2,
      'Data':347.0,'DataList':355.0,'DataSprite':362.4,'NodeSprite':366.5,
      'render':374.0,'ScaleBinding':377.4,'Tree':382.8,
      'Legend':374.2,'LegendItem':383.3,'LegendRange':384.9,
      'distortion':388.7,'encoder':394.5,'filter_op':399.0,'label':403.3,'layout':410.5,
      'AxisLayout':410.5,'CircleLayout':413.4,'CirclePackingLayout':416.0,
      'ForceDirectedLayout':420.8,'IcicleTreeLayout':424.5,
      'RadialTreeLayout':426.8,'StackedAreaLayout':430.2,
      'BifocalDistortion':388.7,'Distortion':390.6,'FisheyeDistortion':393.0
    };

    var MODULES = [
      { name:'analytics', val:'48,716', ci:1 },
      { name:'animate', val:'93,278', ci:2 },
      { name:'data', val:'30,284', ci:3 },
      { name:'display', val:'24,254', ci:4 },
      { name:'flex', val:'4,877', ci:5 },
      { name:'physics', val:'29,934', ci:6 },
      { name:'query', val:'75,492', ci:7 },
      { name:'scale', val:'31,294', ci:8 },
      { name:'util', val:'91,480', ci:2 }
    ];

    var makeEl = ctx.el;
    var depthTotal = [0, 0, 0, 0, 0];
    var depthIndex = [0, 0, 0, 0, 0];
    var cellNodes = [];
    var colorTargets = [];
    var revealDelays = [];
    var plotShiftX = 0;

    nodes.forEach(function (node) {
      depthTotal[node[2]] += 1;
    });

    function formatNodeLabel(name) {
      var maxLength = Math.floor(COL_W / 5.8);
      return name.length > maxLength ? name.slice(0, Math.max(0, maxLength - 3)) + '...' : name;
    }

    function renderLegend() {
      ctx.initStandardLegend({
        legendEl: legendRoot,
        title: 'MODULE',
        items: MODULES.map(function (module) {
          return {
            label: module.name,
            value: module.val,
            swatchStyle: 'fill:' + ctx.getSeriesDepthColor(module.ci, 1)
          };
        })
      });
    }

    function buildCells() {
      nodes.forEach(function (node) {
        var name = node[0];
        var val = node[1];
        var depth = node[2];
        var ci = node[3];
        var x = colX(depth);
        var y = yPos[name] || 100;
        var height = Math.max(1.5, val * SCALE_Y);
        var idx = depthIndex[depth]++;
        var step = Math.min(0.25, COL_ANIM_WINDOW / Math.max(depthTotal[depth], 1));
        var delay = COL_START[depth] + idx * step;
        var cell = makeEl('g', {
          'class': 'icell',
          'data-name': name,
          'data-val': String(val),
          'data-depth': String(depth),
          'data-ci': String(ci)
        });
          var rect = makeEl('rect', {
            x: x,
            y: y,
            width: COL_W,
            height: height,
            fill: ctx.getSeriesDepthColor(ci, depth),
            stroke: 'white',
            'stroke-width': '1',
            rx: depth < 2 ? 3 : 2
        });

        cell.appendChild(rect);
        if (height >= 13) {
          var text = makeEl('text', {
            x: x + 6,
            y: y + height / 2,
            'dominant-baseline': 'central',
            'font-size': depth <= 1 ? 10 : 9,
            'font-weight': depth <= 1 ? '500' : '400',
            fill: 'white',
            'fill-opacity': depth >= 3 ? '0.85' : '1',
            'pointer-events': 'none'
          });
          text.textContent = formatNodeLabel(name);
          cell.appendChild(text);
        }

        dataLayerEl.appendChild(cell);
        cellNodes.push(cell);
        colorTargets.push({ rect: rect, ci: ci, depth: depth });
        revealDelays.push(delay);
      });
    }

    function recolor() {
      colorTargets.forEach(function (target) {
        target.rect.setAttribute('fill', ctx.getSeriesDepthColor(target.ci, target.depth));
      });
      renderLegend();
    }

    buildCells();
    renderLegend();
    plotShiftX = ctx.rebalancePlotArea({
      legendEl: legendRoot,
      measureNodes: [dataLayerEl, xLabelsEl],
      moveNodes: [dataLayerEl, xLabelsEl],
      outerLeft: 24,
      legendGap: 32
    }).shiftX || 0;

    ctx.initRevealSequence(cellNodes, {
      animationName: 'cellFade',
      duration: REVEAL_DURATION,
      easing: 'ease-out',
      delays: revealDelays
    });

    ctx.initStandardTooltip(dataLayerEl, cellNodes, {
      tip: document.getElementById('tip'),
      plotL: 68,
      plotR: 850,
      plotT: 100,
      plotB: 500,
      placement: 'side',
      minWidth: 260,
      paddingX: 20,
      paddingY: 30,
      lineHeights: [42, 32, 32],
      getContent: function (itemEl) {
        var val = parseInt(itemEl.getAttribute('data-val'), 10);
        return {
          primary: val.toLocaleString() + ' lines',
          label: itemEl.getAttribute('data-name') || '',
          meta: (val / TOTAL * 100).toFixed(1) + '% of total'
        };
      },
      getAnchor: function (itemEl) {
        var box = itemEl.getBBox();
        return {
          x: box.x + box.width / 2 + plotShiftX,
          y: box.y + box.height / 2
        };
      },
      onActivate: function (itemEl) {
        dataLayerEl.classList.add('hovering');
        cellNodes.forEach(function (node) {
          node.classList.toggle('hovered', node === itemEl);
        });
      },
      onDeactivate: function () {
        dataLayerEl.classList.remove('hovering');
        cellNodes.forEach(function (node) {
          node.classList.remove('hovered');
        });
      },
      leaveTarget: dataLayerEl
    });

    ctx.markReadyAfterReveal(dataLayerEl, {
      delays: revealDelays,
      duration: REVEAL_DURATION,
      buffer: 0.1
    });

    svgEl._onModeChange = function () { recolor(); };

    recolor();
  };

  if (window.bootstrapChart) { window.bootstrapChart(svg); }
}());
